-- W1.4 new questions batch 517/4739 (10)

INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('social-worker-moex-05780', 'social-worker', 'social-worker-moex-105-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '依英國1989年社區照顧白皮書指出，社區照顧（community care）係指提供適當程度的介入和支持，以 使得人們能獲得最大的自主性，且能夠掌控自己的生活。為實現此目標，下列敘述何者是社區照顧場所？', '["長期的醫院照顧", "老人文康活動中心", "身心障礙者輔具資源中心", "休閒旅遊中心"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "0637ff9598cc", "answer_pdf_sha1": "e5cfd3dd419e", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05781', 'social-worker', 'social-worker-moex-105-694fe135', 'sub-social-worker-03', NULL, 'essay', '從事社區工作並不是一件簡單的事，要永續經營一個社區更非易事。有學者認為社
區價值（community value）、社區能力（community capacity）及社會資本（social
capital）三個項目，是社區永續發展不可或缺的基礎。三者其中之一的社區能力，
根據臺灣學者引述國外學者吉利克曼與莎蒙（Glickman & Servon, 1998）的主張認為
社區能力包含五種能力，請說明這五種能力的內涵，並以實務經驗舉例之。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "32686bdfbc3d", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "社會工作直接服務", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05782', 'social-worker', 'social-worker-moex-105-694fe135', 'sub-social-worker-03', NULL, 'essay', '最近常聽到一些大學社工系教「社會團體工作」的老師感嘆說：「目前在臺灣社工
實務界的社工人員越來越少願意做團體工作，他們都把帶團體的工作委託給團體諮
商專家，社工自己都不做也不學，真擔心有一天社工會變成不會做團體工作的專
業。我們有一種「不知為何而教」的焦慮與沮喪。」而國外的專家也認為大部分的
團體工作實習學生或新進工作者對帶領團體會有一些恐懼的情緒。請問團體工作實
習學生或新進工作者對帶領團體會有那些恐懼的情緒？這些恐懼的情緒要如何克
服，請舉出其中五種恐懼的情緒及其克服的方法，並以實務經驗舉例之。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "32686bdfbc3d", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "社會工作直接服務", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05783', 'social-worker', 'social-worker-moex-105-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列關於專業關係（professional relationship）的敘述，何者錯誤？', '["是指專業人員間的互動連結網絡", "是交互及動態的關係", "個案及其家庭成員、學校教師、有關機構的人員都是專業關係建立的對象", "缺乏專業關係的服務難稱為專業服務"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "32686bdfbc3d", "answer_pdf_sha1": "071b06d8e010", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05784', 'social-worker', 'social-worker-moex-105-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '關於社會工作會談，下列何者錯誤？', '["依會談地點可分為辦公室會談和非辦公室會談", "依會談性質分為預估性會談、治療性會談及教育性會談", "應向案主說明在服務期間對案主的行為要求或限制", "當社會工作人員與案主均已盡力，但問題改善空間不足，可以結束會談"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "32686bdfbc3d", "answer_pdf_sha1": "071b06d8e010", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05785', 'social-worker', 'social-worker-moex-105-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '關於接案會談（the intake interview）的敘述，下列何者錯誤？', '["是個案工作程序中的首要步驟", "必須在機構的會談室進行，並保持45度角的位置安排", "對於不合資格的申請者，應在接案時予以婉辭", "需確認緊急狀況，並給予快速且有效的關注"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "32686bdfbc3d", "answer_pdf_sha1": "071b06d8e010", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05786', 'social-worker', 'social-worker-moex-105-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列對多面向評估的相關敘述何者正確？①評估是一個動態性的過程  ②知識理論會影響評估的進行', '["案主的優勢是需要被評估的", "評估強調此時此刻，過去不重要", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "32686bdfbc3d", "answer_pdf_sha1": "071b06d8e010", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 4, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05787', 'social-worker', 'social-worker-moex-105-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列關於個案工作診斷（casework diagnosis）的敘述，何者錯誤？', '["是個案工作程序的第一步驟", "社會工作人員必須依專業知識和技術歸納整理與分析", "診斷同時必須規劃出個案工作服務或治療的計畫", "是社會工作人員專業的表現"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "32686bdfbc3d", "answer_pdf_sha1": "071b06d8e010", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05788', 'social-worker', 'social-worker-moex-105-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '以下對社區照顧的說法，何者正確？①是以機構為導向的服務  ②是一種社區正式照顧的資源  ③立意', '["可以增加參與和選擇的機會  ⑤是一種以去機構化的方式照顧有需要的居民", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "32686bdfbc3d", "answer_pdf_sha1": "071b06d8e010", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 6, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05789', 'social-worker', 'social-worker-moex-105-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '關於社區培力（empowerment），下列何者正確？', '["重點在於促進個人對自己的環境有掌握控制的經驗", "是運用在個人與人際之間，不是團體與鄰里的資源", "提升社區居民能力是組織的責任，而非對抗不正義", "將社區的居民視為資源，而不是要被協助的案主"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "32686bdfbc3d", "answer_pdf_sha1": "071b06d8e010", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
